@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle italic
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #000000
skinparam classArrowColor #000000
skinparam classStereotypeStyle none

class "ListenAble" as ListenAble {
    void addListener(VoidCallback listener)
    void removeListener(VoidCallback listener)
}

class "ValueListenAble" as ValueListenAble {
    T get value
}

class "ChangeNotifier" as ChangeNotifier {
    ObserverList<VoidCallback> _listeners
    bool get hasListeners
    void dispose()
    void notifyListeners()
}

class "ValueNotifier" as ValueNotifier {
    T get value
    set value(T newValue)
}

ListenAble <|-- ValueListenAble
ListenAble <|.. ChangeNotifier
ValueListenAble <|.. ValueNotifier
ChangeNotifier <|-- ValueNotifier

note right of ValueListenAble: T
note right of ValueNotifier: T

@enduml
